"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
export default function BeaconSignalButton() { const [sent, setSent] = useState(false); const reduced = useReducedMotion(); return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">Release note</p><motion.button type="button" onClick={() => setSent(!sent)} whileTap={reduced ? undefined : { scale: .97 }} className="mt-4 flex min-h-11 w-full items-center justify-between rounded-2xl bg-[#111] px-4 py-3 font-bold text-white outline-offset-4 focus-visible:outline focus-visible:outline-2 focus-visible:outline-[#111]"><span className="flex items-center gap-2"><motion.i aria-hidden className="h-2.5 w-2.5 rounded-full bg-[#53e8d4]" animate={sent && !reduced ? { scale: [1, 1.8, 1], opacity: [1, .4, 1] } : { scale: 1, opacity: 1 }} transition={{ duration: .48 }}/>{sent ? "Sent update" : "Send update"}</span><span aria-hidden>→</span></motion.button><p aria-live="polite" className="mt-3 min-h-5 text-sm text-[#4a4a4f]">{sent ? "Update is ready for review." : "One clear action, keyboard ready."}</p></section>; }
